// flows/AllergyCrossReactivity.flow.mind
// ClinicalMem — SNOMED CT drug-class cross-reactivity check.
// Apache-2.0 (see LICENSE)
//
// Catches prescriptions that cross-react with documented allergies
// via the 8-class SNOMED CT hierarchy: penicillin, cephalosporin,
// sulfonamide, fluoroquinolone, opioid, NSAID, ACE inhibitor, statin.
//
// Demo case: amoxicillin prescribed for a patient with documented
// penicillin anaphylaxis → catch via β-lactam class hierarchy.
//
//     medications + allergies ─► phi_scan ─► snomed_resolve ─► class_match ─► severity_score ─► report

@profile "regulated_online"
flow AllergyCrossReactivity {
    input  patient_id:    PatientId
    input  medications:   MedicationList
    input  allergies:     AllergyList
    output cross_reacts:  CrossReactivityReport

    node phi = @native phi_scan(medications, allergies)
    invariant phi.safe_for_external == true

    node med_classes = @native snomed_resolve_drug_classes(medications)
    node allergy_classes = @native snomed_resolve_allergy_classes(allergies)

    invariant med_classes.coverage_ratio >= 0.90
    invariant allergy_classes.coverage_ratio >= 0.90

    node matches = @native class_hierarchy_match(med_classes, allergy_classes)

    node scored = @native severity_score(
        matches:    matches,
        severity_table: "snomed_class_cross_reactivity_v1",
    )

    node audit = @native emit_audit_chain(
        plan_hash: $plan_hash,
        nodes:     [phi, med_classes, allergy_classes, matches, scored],
        tag:       "TAG_v1",
    )

    assign cross_reacts = @native build_cross_reactivity_report(scored, audit)
}

// flows/ClinicalTrialMatch.flow.mind
// ClinicalMem — ClinicalTrials.gov eligibility match.
// Apache-2.0 (see LICENSE)
//
// Surfaces active clinical trials matching a patient's condition list
// and pre-screens eligibility against trial criteria (age, gender,
// active conditions, exclusion medications).
//
//     patient + conditions ─► phi_scan ─► trial_search ─► eligibility_screen ─► rank ─► report

@profile "regulated_online"
flow ClinicalTrialMatch {
    input  patient_id:   PatientId
    input  conditions:   ConditionList
    input  demographics: PatientDemographics
    output matches:      TrialMatchReport

    node phi = @native phi_scan(conditions, demographics)
    invariant phi.safe_for_external == true

    // Query ClinicalTrials.gov for active trials matching condition list
    node candidates = @native search_clinical_trials(
        conditions:  conditions,
        status:      "Recruiting",
        country:     "US",
        max_results: 50,
    )

    // Pre-screen eligibility against age, gender, active conditions,
    // exclusion medications, and required lab thresholds.
    node screened = @native eligibility_screen(
        trials:       candidates,
        demographics: demographics,
        conditions:   conditions,
    )
    invariant screened.fairness_audit_passed == true   // avoid demographic-bias drift

    // Rank by clinical relevance (LLM-grounded; cites the trial document)
    node ranked = @llm rank_trial_relevance(
        trials:    screened,
        require_citations: true,
    )
    invariant ranked.citations_valid == true

    node audit = @native emit_audit_chain(
        plan_hash: $plan_hash,
        nodes:     [phi, candidates, screened, ranked],
        tag:       "TAG_v1",
    )

    assign matches = @native build_trial_match_report(ranked, audit)
}

// flows/LabContraindication.flow.mind
// ClinicalMem — declining-lab + medication contraindication check.
// Apache-2.0 (see LICENSE)
//
// Catches medications becoming contraindicated as labs trend toward
// thresholds. Demo case: GFR dropping 45 → 32 over 6 months while
// patient is on metformin (contraindicated below GFR 30).
//
//     medications + labs ─► phi_scan ─► trend_analyze ─► contraindication_match ─► severity_score ─► report

@profile "regulated_online"
flow LabContraindication {
    input  patient_id:     PatientId
    input  medications:    MedicationList
    input  lab_history:    LabHistoryWindow
    output contraindications: ContraindicationReport

    node phi = @native phi_scan(medications, lab_history)
    invariant phi.safe_for_external == true

    // Compute lab trends (linear regression over the window)
    node trends = @native lab_trend_analyze(
        history: lab_history,
        window_months: 6,
    )

    // Match med-lab contraindication rules (e.g. metformin ⊥ GFR < 30)
    node matches = @native contraindication_match(
        medications: medications,
        trends:      trends,
        rules_table: "med_lab_contraindication_v1",
    )

    invariant matches.threshold_proximity_valid == true

    node scored = @native severity_score(
        matches: matches,
        severity_table: "lab_proximity_severity_v1",
    )

    node audit = @native emit_audit_chain(
        plan_hash: $plan_hash,
        nodes:     [phi, trends, matches, scored],
        tag:       "TAG_v1",
    )

    assign contraindications = @native build_contraindication_report(scored, audit)
}

// flows/MedicationSafetyReview.flow.mind
// ClinicalMem — five-tier drug-interaction safety review.
// Apache-2.0 (see LICENSE)
//
// Catches interactions like NSAID + warfarin → fatal bleeding risk.
// The flow's content-addressed plan_hash is recorded in the audit
// chain for every clinical decision; a regulator with this file and
// the inputs replays the same plan and asserts byte-identical output.
//
// Pipeline (left-to-right composition):
//
//     medications ─► phi_scan ─► normalize ─► tier1 ─► tier2 ─► tier3 ─► bitnet ─► consensus ─► synthesize ─► report
//
// Every `@verify` invariant is enforced at runtime; a violation
// returns a structured InvariantViolation rather than a possibly-
// wrong clinical answer. In healthcare, "I don't know" saves lives.

@profile "regulated_online"
@kernel  "guarded"
flow MedicationSafetyReview {
    input  patient_id:   PatientId
    input  medications:  MedicationList
    output report:       SafetyReport

    // ───── PHI guard ────────────────────────────────────────────
    node phi = @native phi_scan(medications)
    invariant phi.safe_for_external == true

    // ───── Normalize medication names → RxCUI ──────────────────
    node normalized = @native rxnorm_normalize(medications)
    invariant normalized.coverage_ratio >= 0.95   // ≥ 95% pairs resolved

    // ───── Tier 1: deterministic table (microseconds) ──────────
    node tier1 = @native deterministic_table_check(normalized)

    // ───── Tier 2: OpenEvidence (Mayo / Elsevier ClinicalKey AI) ─
    node tier2 = @native openevidence_lookup(normalized, tier1.uncovered)

    // ───── Tier 3: NIH RxNorm Drug Interaction API ─────────────
    node tier3 = @native nih_drug_interaction_lookup(normalized, tier2.uncovered)

    // ───── Tier 4.5: BitNet b1.58 ternary classifier ────────────
    // Q16.16 fixed-point forward; bit-identical across architectures.
    // FDA SaMD reproducibility primitive: every output carries a
    // repro_hash that any auditor can re-verify in <1 ms per pair.
    node bitnet = @native bitnet_ternary_classify(normalized)

    // ───── Tier 4: 5-model US-based LLM consensus ───────────────
    node consensus = @llm consensus(
        prior:       [tier1, tier2, tier3, bitnet],
        models:      ["gpt-5.5", "gemini-3.1-pro",
                      "grok-4.3", "claude-opus-4.7", "sonar-pro"],
        majority_or_abstain: true,
    )
    invariant consensus.available_models >= 4
    invariant consensus.majority_or_abstain == true

    // ───── Synthesis (LLM) — explanation grounded in evidence ──
    node synth = @llm synthesize(
        findings:    [tier1, tier2, tier3, bitnet, consensus],
        require_citations: true,
    )
    invariant synth.citations_valid == true
    invariant synth.unsupported_claims == 0

    // ───── Audit chain — every node hash-linked to plan_hash ───
    node audit = @native emit_audit_chain(
        plan_hash:   $plan_hash,
        nodes:       [phi, normalized, tier1, tier2, tier3, bitnet, consensus, synth],
        tag:         "TAG_v1",
    )

    assign report = @native build_safety_report(synth, audit)
}

// flows/ProviderDisagreement.flow.mind
// ClinicalMem — cross-provider contradiction detection.
// Apache-2.0 (see LICENSE)
//
// Catches conflicting care plans across multiple providers. Demo case:
// cardiologist's BP target <130/80 vs nephrologist's <140/90 for the
// same patient.
//
//     provider_records ─► phi_scan ─► claim_extract ─► contradiction_detect ─► resolution_suggest ─► report

@profile "regulated_online"
flow ProviderDisagreement {
    input  patient_id:        PatientId
    input  provider_records:  ProviderRecordList
    output disagreements:     DisagreementReport

    node phi = @native phi_scan(provider_records)
    invariant phi.safe_for_external == true

    // Extract typed clinical claims (BP target, medication regimen,
    // diagnostic agreement, treatment plan) from each provider record.
    node claims = @native extract_clinical_claims(provider_records)
    invariant claims.coverage_ratio >= 0.85

    // Detect harmful contradictions (NOT acceptable specialty nuance).
    node contradictions = @native detect_contradictions(
        claims:                claims,
        nuance_filter:         "specialty_disagreement_v1",
        severity_threshold:    "moderate",
    )

    // Suggest resolution strategies (escalate to PCP, request reconciliation,
    // surface for nurse review).
    node resolution = @llm suggest_resolution(
        contradictions: contradictions,
        require_grounded_in: claims,
    )
    invariant resolution.citations_valid == true

    node audit = @native emit_audit_chain(
        plan_hash: $plan_hash,
        nodes:     [phi, claims, contradictions, resolution],
        tag:       "TAG_v1",
    )

    assign disagreements = @native build_disagreement_report(
        contradictions, resolution, audit
    )
}

// flows/WhatIfSimulation.flow.mind
// ClinicalMem — what-if medication preview.
// Apache-2.0 (see LICENSE)
//
// Lets a clinician simulate adding/removing/substituting a medication
// before making the change. Runs the full five-tier safety pipeline
// against the hypothetical regimen and surfaces diffs vs the current
// regimen.
//
// Demo flow: "What if we add aspirin to a patient already on warfarin?"
//
//     current + perturbation ─► resolve_target ─► run_review ─► diff ─► report

@profile "regulated_online"
flow WhatIfSimulation {
    input  patient_id:    PatientId
    input  current:       MedicationList
    input  perturbation:  MedicationPerturbation   // add | remove | substitute
    output preview:       SafetyDiffReport

    // Resolve the target regimen (apply the perturbation)
    node target = @native apply_perturbation(current, perturbation)
    invariant target.well_formed == true

    // Run the five-tier safety review on the hypothetical regimen.
    // This is the SAME contract as MedicationSafetyReview.flow.mind —
    // any change there propagates here automatically.
    node review_current = @flow MedicationSafetyReview(
        patient_id:  patient_id,
        medications: current,
    )
    node review_target = @flow MedicationSafetyReview(
        patient_id:  patient_id,
        medications: target,
    )

    invariant review_current.report.complete == true
    invariant review_target.report.complete  == true

    // Diff: which findings appeared / disappeared / changed severity
    node diff = @native compute_safety_diff(
        before: review_current.report,
        after:  review_target.report,
    )

    // LLM-grounded narrative explaining the diff in plain language
    node narrative = @llm explain_safety_diff(
        diff: diff,
        require_grounded_in: [review_current.report, review_target.report],
    )
    invariant narrative.citations_valid == true

    node audit = @native emit_audit_chain(
        plan_hash: $plan_hash,
        nodes:     [target, review_current, review_target, diff, narrative],
        tag:       "TAG_v1",
    )

    assign preview = @native build_safety_diff_report(diff, narrative, audit)
}
